commands.cmd:
raw=$(cat /proc/sys/kernel/tainted) || { echo "tainted unreadable" >&2; exit 1; }
printf '%s\n' "$raw" | awk '
  {
    v=$1
    if (v=="") { print "tainted value missing" > "/dev/stderr"; exit 1 }
    n=split("proprietary-module-loaded,module-force-loaded,cpu-out-of-spec,module-force-unloaded,machine-check,bad-page,user-forced,kernel-died,acpi-table-overridden,kernel-warning,staging-driver-loaded,firmware-workaround,out-of-tree-module,unsigned-module,soft-lockup,live-patched,auxiliary-taint,struct-randomized", names, ",")
    flags=""
    for (i=0; i<n; i++) {
      if (int(v / (2^i)) % 2 == 1) {
        flags=(flags=="" ? names[i+1] : flags "," names[i+1])
      }
    }
    printf "{\"tainted\":%d,\"flags\":\"%s\"}", v, flags
  }' || exit 1
